"""
server.py
Microdot REST API served on port 80 for KegLevel Brain.

All endpoints return JSON.  The KegLevel Brain app on the host (Pi / Windows /
Mac) polls /api/state every ~500 ms and uses the remaining endpoints for
library management, configuration, calibration, and system operations.

Endpoint summary
  GET  /api/state                        — live tap state + keg info + temperature
  GET  /api/version                      — firmware version

  GET  /api/config                       — system config (k-factors, taps, labels)
  PUT  /api/config                       — update system config

  GET  /api/kegs                         — all keg records
  POST /api/kegs                         — create keg
  GET  /api/kegs/<keg_id>                — single keg
  PUT  /api/kegs/<keg_id>                — update keg fields
  DELETE /api/kegs/<keg_id>              — delete keg

  GET  /api/beverages                    — full beverage catalog
  POST /api/beverages                    — create beverage
  GET  /api/beverages/<bev_id>           — single beverage
  PUT  /api/beverages/<bev_id>           — update beverage
  DELETE /api/beverages/<bev_id>         — delete beverage

  GET  /api/taps                         — tap config (assignments, k-factors, labels)
  PUT  /api/taps/<tap_n>                 — assign keg, set k-factor / label for tap
  POST /api/taps/<tap_n>/reset           — zero dispensed counter (keg change)
  POST /api/taps/<tap_n>/calibrate/start — begin K-factor calibration
  POST /api/taps/<tap_n>/calibrate/stop  — end calibration, return pulse count
  GET  /api/taps/<tap_n>/calibrate       — read running calibration pulse count

  GET  /api/alerts/config                — alert settings (Mailgun creds, thresholds)
  PUT  /api/alerts/config                — update alert settings
  POST /api/alerts/test                  — send a test email immediately

  GET  /api/history                      — recent pour log

  GET  /api/batchflow                    — BatchFlow workflow state
  PUT  /api/batchflow                    — save BatchFlow workflow state

  POST /api/wifi/reset                   — erase WiFi credentials, reboot to portal
  POST /api/update                       — OTA: receive a .py or web file and write to flash
"""

import gc
import json
import os
import machine
import asyncio

from microdot import Microdot, Request, Response

# OTA pushes .py files (microdot.py ~60KB + JSON); 16KB default triggers 413
Request.max_content_length = 256 * 1024
Request.max_body_length = 256 * 1024

import sensor
import temperature
import config_manager
import alert_manager
import diagnostic
from version import FIRMWARE_VERSION
from wifi import get_ip

app = Microdot()

_CORS = {
    "Access-Control-Allow-Origin": "*",
    "Content-Type": "application/json",
}

# CORS headers for preflight (OPTIONS) and error responses
_CORS_PREFLIGHT = {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type",
    "Access-Control-Max-Age": "86400",
}


def _cors_options_handler(req):
    """Handle OPTIONS preflight with CORS headers for cross-origin web clients."""
    allow = []
    for route_methods, route_pattern, _, _, _ in app.url_map:
        if route_pattern.match(req.path) is not None:
            allow.extend(route_methods)
    if "GET" in allow:
        allow.append("HEAD")
    allow.append("OPTIONS")
    headers = dict(_CORS_PREFLIGHT)
    headers["Allow"] = ", ".join(allow)
    return headers


app.options_handler = _cors_options_handler


def _add_cors_to_response(req, res):
    """Add CORS headers to error responses (404, 405, 500, etc.)."""
    for k, v in _CORS_PREFLIGHT.items():
        res.headers[k] = v
    return res


app.after_error_request(_add_cors_to_response)


def _json(data, status=200):
    return Response(json.dumps(data), status, headers=_CORS)


def _error(msg, status=400):
    return _json({"error": msg}, status)


def _validate_tap(tap_n) -> tuple:
    """Parse tap_n string to int 0-4.  Returns (idx, None) or (-1, error_response)."""
    try:
        idx = int(tap_n)
        if not (0 <= idx <= 4):
            raise ValueError
        return idx, None
    except (ValueError, TypeError):
        return -1, _error("tap_n must be 0–4.")


# ---------------------------------------------------------------------------
# /api/state/fast — lightweight poll during active pours (minimal JSON)
# ---------------------------------------------------------------------------

@app.route("/api/state/fast", methods=["GET"])
async def get_state_fast(request):
    """
    Lightweight tap state for fast polling during pours.
    Returns minimal tap data (no keg enrichment) and temperature.
    Used when app is in fast-poll mode to reduce Pico load per request.
    """
    snapshots = sensor.get_all_snapshots()

    taps = []
    for snap in snapshots:
        i    = snap["index"]
        keg  = config_manager.get_keg_for_tap(i)
        disp = snap["dispensed_liters"]
        if keg:
            start     = keg.get("starting_volume_liters", 0.0)
            remaining = start - disp
        else:
            remaining = 0.0
        taps.append({
            "index":            i,
            "dispensed_liters": round(disp, 4),
            "remaining_liters": round(remaining, 4),
            "pouring":          snap["pouring"],
            "flow_rate_lpm":    snap["flow_rate_lpm"],
            "lifetime_pulses":  snap["lifetime_pulses"],
        })

    cal = sensor.get_calibration_status()
    return _json({
        "taps":        taps,
        "temperature": temperature.get_temperature_data(),
        "calibration": cal,
    })


# ---------------------------------------------------------------------------
# /api/state  — primary poll endpoint (idle / full enrichment)
# ---------------------------------------------------------------------------

@app.route("/api/state", methods=["GET"])
async def get_state(request):
    """
    Returns live sensor data enriched with keg library info.
    The app can display everything it needs from this single endpoint.
    Remaining volume is computed here: keg.starting_volume - sensor.dispensed[tap].
    """
    cfg       = config_manager.get_config()
    snapshots = sensor.get_all_snapshots()

    enriched_taps = []
    for snap in snapshots:
        i   = snap["index"]
        keg = config_manager.get_keg_for_tap(i)
        if keg:
            starting  = keg.get("starting_volume_liters", 0.0)
            disp      = snap["dispensed_liters"]
            remaining = starting - disp
        else:
            starting  = 0.0
            remaining = 0.0

        entry = dict(snap)
        entry["remaining_liters"]       = round(remaining, 4)
        entry["starting_volume_liters"] = round(starting, 4)
        entry["maximum_full_volume_liters"] = round(keg.get("maximum_full_volume_liters", 18.93), 4) if keg else 0
        entry["keg_id"]                 = keg["id"]                    if keg else ""
        entry["keg_name"]               = keg.get("name", "")          if keg else ""
        entry["beverage_name"]          = keg.get("beverage_name", "") if keg else ""
        entry["style"]                  = keg.get("style", "")         if keg else ""
        entry["abv"]                    = keg.get("abv", 0.0)          if keg else 0.0
        ibu                             = ""
        srm                             = None
        if keg and keg.get("beverage_id"):
            bev = config_manager.get_beverage_by_id(keg["beverage_id"])
            if bev:
                if bev.get("ibu") not in (None, ""):
                    ibu = int(bev["ibu"])
                if bev.get("srm") is not None:
                    srm = int(bev["srm"])
        entry["ibu"]                    = ibu
        entry["srm"]                    = srm
        entry["tap_label"]              = cfg["tap_labels"][i] if i < len(cfg["tap_labels"]) else f"Tap {i+1}"
        enriched_taps.append(entry)

    cal = sensor.get_calibration_status()
    wifi_cfg = config_manager.get_wifi()
    return _json({
        "taps":           enriched_taps,
        "temperature":    temperature.get_temperature_data(),
        "active_taps":    cfg["active_taps"],
        "any_pouring":    sensor.any_tap_pouring(),
        "ip":             get_ip(),
        "version":        FIRMWARE_VERSION,
        "calibration":    cal,
        "wifi_mode":      wifi_cfg.get("mode", "sta"),
        "leak_warnings":  sensor.get_leak_status(),
    })


# ---------------------------------------------------------------------------
# /api/version
# ---------------------------------------------------------------------------

@app.route("/api/version", methods=["GET"])
async def get_version(request):
    return _json({"version": FIRMWARE_VERSION})


# ---------------------------------------------------------------------------
# /api/config  — system config (k-factors, active taps, tap labels)
# ---------------------------------------------------------------------------

@app.route("/api/config", methods=["GET"])
async def get_config(request):
    cfg = dict(config_manager.get_config())
    cfg.pop("alerts", None)   # alert config is served via /api/alerts/config
    return _json(cfg)


@app.route("/api/config", methods=["PUT"])
async def put_config(request):
    try:
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")

        patch = {}

        if "k_factors" in body:
            kf = body["k_factors"]
            if not isinstance(kf, list) or len(kf) != 5:
                return _error("k_factors must be a list of 5 numbers.")
            patch["k_factors"] = [max(1.0, float(x)) for x in kf]

        if "active_taps" in body:
            patch["active_taps"] = max(1, min(5, int(body["active_taps"])))

        if "tap_labels" in body:
            labels = body["tap_labels"]
            if not isinstance(labels, list) or len(labels) != 5:
                return _error("tap_labels must be a list of 5 strings.")
            patch["tap_labels"] = [str(l) for l in labels]

        if "mdns_hostname" in body:
            hn = str(body["mdns_hostname"]).lower().strip().replace(".local", "")
            if hn:
                patch["mdns_hostname"] = hn
                try:
                    import mdns
                    mdns.set_hostname(hn)
                except Exception:
                    pass

        if "leak_detection_enabled" in body:
            patch["leak_detection_enabled"] = bool(body["leak_detection_enabled"])

        config_manager.update_config(patch)
        sensor.apply_config(config_manager.get_config())

        result = dict(config_manager.get_config())
        result.pop("alerts", None)
        return _json({"status": "ok", "config": result})
    except Exception as e:
        return _error(str(e))


# ---------------------------------------------------------------------------
# /api/kegs  — keg library CRUD
# ---------------------------------------------------------------------------

@app.route("/api/kegs", methods=["GET"])
async def list_kegs(request):
    return _json(config_manager.get_kegs())


@app.route("/api/kegs", methods=["POST"])
async def create_keg(request):
    try:
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")
        if not body.get("name", "").strip():
            return _error("'name' is required.")
        keg = config_manager.create_keg(body)
        return _json(keg, 201)
    except Exception as e:
        return _error(str(e))


@app.route("/api/kegs/<keg_id>", methods=["GET"])
async def get_keg(request, keg_id):
    keg = config_manager.get_keg_by_id(keg_id)
    if keg is None:
        return _error(f"Keg '{keg_id}' not found.", 404)
    return _json(keg)


@app.route("/api/kegs/<keg_id>", methods=["PUT"])
async def update_keg(request, keg_id):
    try:
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")
        keg = config_manager.update_keg(keg_id, body)
        if keg is None:
            return _error(f"Keg '{keg_id}' not found.", 404)
        return _json(keg)
    except Exception as e:
        return _error(str(e))


@app.route("/api/kegs/<keg_id>", methods=["DELETE"])
async def delete_keg(request, keg_id):
    deleted = config_manager.delete_keg(keg_id)
    if not deleted:
        return _error(f"Keg '{keg_id}' not found.", 404)
    return _json({"status": "ok", "deleted": keg_id})


