@app.route("/api/beverages/<bev_id>", methods=["PUT"])
async def update_beverage(request, bev_id):
    try:
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")
        bev = config_manager.update_beverage(bev_id, body)
        if bev is None:
            return _error(f"Beverage '{bev_id}' not found.", 404)
