# ---------------------------------------------------------------------------
# /api/taps  — tap configuration and keg assignment
# ---------------------------------------------------------------------------

@app.route("/api/taps", methods=["GET"])
async def get_taps(request):
    """Return all tap configuration including current keg assignments."""
    cfg       = config_manager.get_config()
    state     = config_manager.get_state()
    dispensed = state.get("dispensed_liters", [0.0] * 5)
    taps      = []
    for i in range(5):
        keg = config_manager.get_keg_for_tap(i)
        taps.append({
            "index":       i,
            "active":      i < cfg["active_taps"],
            "label":       cfg["tap_labels"][i] if i < len(cfg["tap_labels"]) else f"Tap {i+1}",
            "k_factor":    cfg["k_factors"][i]  if i < len(cfg["k_factors"])  else 2900.0,
            "keg_id":      keg["id"]         if keg else "",
            "keg_name":    keg.get("name","") if keg else "",
            "dispensed_liters": round(dispensed[i], 4) if i < len(dispensed) else 0.0,
        })
    return _json(taps)


@app.route("/api/taps/<tap_n>/adjust", methods=["POST"])
async def adjust_tap_dispensed(request, tap_n):
    """Add simulated volume to the sensor-level dispensed counter.
    Body: {"liters": <float>}"""
    idx, err = _validate_tap(tap_n)
    if err:
        return err
    try:
        body = request.json or {}
        liters = float(body.get("liters", 0))
        if liters > 0:
            sensor.adjust_dispensed(idx, liters)
        return _json({"status": "ok", "tap": idx, "adjusted_liters": round(liters, 4)})
    except Exception as e:
        return _error(str(e))


@app.route("/api/test/drip", methods=["POST"])
async def test_drip(request):
    """Inject sub-threshold pulses into the ISR accumulator for leak detection testing."""
    body = request.json or {}
    tap = int(body.get("tap", 0))
    pulses = int(body.get("pulses", 5))
    if not (0 <= tap <= 4):
        return _error("tap must be 0-4.")
    pulses = max(1, min(pulses, sensor.POUR_START_PULSES - 1))
    sensor._isr_counts[tap] = pulses
    return _json({"status": "ok", "tap": tap, "pulses": pulses})


@app.route("/api/taps/<tap_n>", methods=["PUT"])
async def update_tap(request, tap_n):
    """
    Assign a keg to a tap, and/or update k-factor / label.

    Body fields (all optional):
      keg_id  — ID of keg to assign; "" or omitted = unassign
      k_factor — new K-factor for this tap
      label   — display label for this tap

    When a new keg is assigned:
      - Any previously assigned keg for this tap is unassigned (tap_index → -1)
      - The new keg's tap_index is set to tap_n
      - Sensor dispensed counter is reset to zero
    """
    idx, err = _validate_tap(tap_n)
    if err:
        return err
    try:
        body = request.json or {}

        cfg   = config_manager.get_config()
        patch = {}

        if "k_factor" in body:
            kf = cfg["k_factors"][:]
            kf[idx] = max(1.0, float(body["k_factor"]))
            patch["k_factors"] = kf

        if "label" in body:
            labels      = cfg["tap_labels"][:]
            labels[idx] = str(body["label"])
            patch["tap_labels"] = labels

        if patch:
            config_manager.update_config(patch)
            sensor.apply_config(config_manager.get_config())

        if "keg_id" in body:
            new_keg_id = str(body["keg_id"]).strip()

            # Unassign any keg currently on this tap
            old_keg = config_manager.get_keg_for_tap(idx)
            if old_keg:
                config_manager.update_keg(old_keg["id"], {"tap_index": -1})

            if new_keg_id:
                new_keg = config_manager.get_keg_by_id(new_keg_id)
                if new_keg is None:
                    return _error(f"Keg '{new_keg_id}' not found.", 404)
                config_manager.update_keg(new_keg_id, {"tap_index": idx})
                sensor.reset_tap(idx)
                print(f"[Server] Tap {idx + 1} assigned keg '{new_keg_id}'")
            else:
                sensor.reset_tap(idx)
                print(f"[Server] Tap {idx + 1} unassigned.")

        return _json({"status": "ok", "tap": idx})
    except Exception as e:
        return _error(str(e))


@app.route("/api/taps/<tap_n>/reset", methods=["POST"])
async def reset_tap(request, tap_n):
    """Zero the dispensed counter for a tap (e.g. after manually noting keg change)."""
    idx, err = _validate_tap(tap_n)
    if err:
        return err
    if sensor.any_tap_pouring():
        return _error("Cannot reset while a pour is active.", 409)
    sensor.reset_tap(idx)
    return _json({"status": "ok", "tap": idx})


# ---------------------------------------------------------------------------
# /api/calibration/standby  — calibration standby (Pico auto-detects flow)
# ---------------------------------------------------------------------------

@app.route("/api/calibration/standby", methods=["POST"])
async def calibration_standby(request):
    """Enable/disable calibration standby. When active, Pico auto-detects flow like runtime."""
    try:
        body = request.json or {}
        active = bool(body.get("active", False))
        sensor.set_calibration_standby(active)
        return _json({"status": "ok", "standby": active})
    except Exception as e:
        return _error(str(e))


@app.route("/api/calibration/reset", methods=["POST"])
async def calibration_reset(request):
    """Clear calibration lock; ready for next tap. Stays in standby if active."""
    sensor.reset_calibration_lock()
    return _json({"status": "ok"})


# ---------------------------------------------------------------------------
# /api/taps/<n>/calibrate  — K-factor calibration (legacy; app uses standby flow)
# ---------------------------------------------------------------------------

@app.route("/api/taps/<tap_n>/calibrate/start", methods=["POST"])
async def calibrate_start(request, tap_n):
    idx, err = _validate_tap(tap_n)
    if err:
        return err
    sensor.start_calibration(idx)
    return _json({"status": "calibrating", "tap": idx,
                  "pulses": sensor.get_calibration_pulses(idx)})


@app.route("/api/taps/<tap_n>/calibrate/stop", methods=["POST"])
async def calibrate_stop(request, tap_n):
    idx, err = _validate_tap(tap_n)
    if err:
        return err
    pulses = sensor.stop_calibration(idx)
    return _json({"status": "done", "tap": idx, "pulses": pulses})


@app.route("/api/taps/<tap_n>/calibrate", methods=["GET"])
async def calibrate_read(request, tap_n):
    idx, err = _validate_tap(tap_n)
    if err:
        return err
    return _json({"tap": idx, "pulses": sensor.get_calibration_pulses(idx)})


# ---------------------------------------------------------------------------
# /api/alerts  — alert configuration and test
# ---------------------------------------------------------------------------

@app.route("/api/alerts/config", methods=["GET"])
async def get_alerts_config(request):
    cfg_alerts = config_manager.get_config().get("alerts", {})
    # Redact API key from GET response — return masked version
    safe = dict(cfg_alerts)
    if safe.get("mailgun_api_key"):
        safe["mailgun_api_key"] = "***"
    return _json(safe)


@app.route("/api/alerts/config", methods=["PUT"])
async def put_alerts_config(request):
    """
    Update alert settings.  Only fields present in the body are changed.
    The full API key must be supplied to update it; if the body contains
    '***' the existing key is left unchanged.
    """
    try:
        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")

        cfg = config_manager.get_config()
        if "alerts" not in cfg:
            cfg["alerts"] = {}

        allowed = (
            "mailgun_api_key", "mailgun_domain", "from_email", "to_email",
            "push_enabled", "push_interval",
            "conditional_enabled",
            "low_volume_threshold_liters",
            "low_temp_threshold_f", "high_temp_threshold_f",
        )
        for field in allowed:
            if field in body:
                val = body[field]
                if field == "mailgun_api_key" and val == "***":
                    continue   # sentinel — keep existing key
                if field in ("low_volume_threshold_liters",
                             "low_temp_threshold_f", "high_temp_threshold_f"):
                    val = float(val)
                elif field in ("push_enabled", "conditional_enabled"):
                    val = bool(val)
                cfg["alerts"][field] = val

        config_manager.save_config(cfg)
        safe = dict(cfg["alerts"])
        if safe.get("mailgun_api_key"):
            safe["mailgun_api_key"] = "***"
        return _json({"status": "ok", "alerts": safe})
    except Exception as e:
        return _error(str(e))


@app.route("/api/alerts/test", methods=["POST"])
async def test_alert(request):
    """Send a test email using current Mailgun credentials."""
    ok, reason = alert_manager.send_test_email()
    if ok:
        return _json({"status": "ok", "message": "Test email sent."})
    return _error(f"Test email failed: {reason}", 502)


# ---------------------------------------------------------------------------
# /api/history  — pour log
# ---------------------------------------------------------------------------

@app.route("/api/history", methods=["GET"])
async def get_history(request):
    return _json(config_manager.get_history())


# ---------------------------------------------------------------------------
# /api/wifi/reset  — erase WiFi credentials and reboot to captive portal
# ---------------------------------------------------------------------------

@app.route("/api/wifi/reset", methods=["POST"])
async def wifi_reset(request):
    sensor.flush_state_now()
    config_manager.clear_wifi()
    asyncio.create_task(_delayed_reset(1000))
    return _json({"status": "rebooting"})


# ---------------------------------------------------------------------------
# /api/update  — OTA firmware update
# ---------------------------------------------------------------------------

_OTA_MANIFEST = "ota_manifest.json"


@app.route("/api/ota/manifest", methods=["GET"])
async def get_ota_manifest(request):
    if _file_exists(_OTA_MANIFEST):
        try:
            with open(_OTA_MANIFEST, "r") as f:
                return _json(json.load(f))
        except Exception:
            pass
    return _json({})


@app.route("/api/ota/manifest", methods=["PUT"])
async def put_ota_manifest(request):
    try:
        body = request.json
        with open(_OTA_MANIFEST, "w") as f:
            json.dump(body, f)
        return _json({"status": "ok"})
    except Exception as e:
        return _error(str(e))


@app.route("/api/update", methods=["POST"])
async def ota_update(request):
    """
    Write a file to flash. Accepts .py firmware and web UI files under www/.

    Body: { "filename": "sensor.py" or "www/batchflow.html", "content": "<source>", "reboot": true }

    Guards:
      - No active pour
      - Allowed extensions: .py, .html, .css, .js
    """
    try:
        gc.collect()
        if sensor.any_tap_pouring():
            return _error("Cannot update during an active pour.", 409)

        body = request.json
        if not isinstance(body, dict):
            return _error("Body must be a JSON object.")

        filename = body.get("filename", "").strip().replace("\\", "/")
        content  = body.get("content",  "")
        reboot   = body.get("reboot",   False)

        _allowed_ext = (".py", ".html", ".css", ".js")
        if not any(filename.endswith(ext) for ext in _allowed_ext):
            return _error("File type not allowed.")
        if filename.startswith("/") or ".." in filename:
            return _error("Invalid path.")

        sensor.flush_state_now()

        append = body.get("append", False)

        if not append:
            # Create parent dirs if needed (e.g. lib/microdot/)
            if "/" in filename:
                acc = []
                for part in filename.split("/")[:-1]:
                    acc.append(part)
                    dirpath = "/".join(acc)
                    try:
                        os.mkdir(dirpath)
                    except OSError:
                        pass

        mode = "a" if append else "w"
        with open(filename, mode) as f:
            f.write(content)

        if not append:
            gz_stale = filename + ".gz"
            if _file_exists(gz_stale):
                try:
                    os.remove(gz_stale)
                    print(f"[OTA] Removed stale {gz_stale}")
                except OSError:
                    pass

        print(f"[OTA] {'Appended' if append else 'Written'} {filename} ({len(content)} bytes)")

        if reboot:
            asyncio.create_task(_delayed_reset(1500))

        return _json({"status": "ok", "filename": filename,
                      "bytes": len(content), "rebooting": reboot})
    except Exception as e:
        print(f"[OTA] Error: {type(e).__name__}: {e}")
        return _error(f"{type(e).__name__}: {e}")


async def _delayed_reset(delay_ms: int):
    await asyncio.sleep_ms(delay_ms)
    machine.reset()


