  background: #252525;
  color: #e0e0e0;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.sub-btn:hover:not(:disabled) {
  background: #333;
}

.sub-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.sub-btn-green {
  background: #166534;
  color: #fff;
  border: none;
}

.sub-btn-green:hover:not(:disabled) {
  background: #15803d;
}

.sub-btn-reload {
  background: #f59e0b;
  color: #1a1a1a;
  border: none;
}

.sub-btn-reload:hover:not(:disabled) {
  background: #fbbf24;
}

/* Screen headers (Kegs, Beverages) */
.screen-header {
  padding: 16px;
  background: #141414;
  border-bottom: 1px solid #222;
}

.screen-header h2 {
  margin: 0;
  font-size: 20px;
  font-weight: 700;
  color: #ffa500;
}

.screen-content {
  flex: 1;
  overflow: auto;
  padding: 16px;
}

.list-header {
  display: grid;
  gap: 12px;
  padding: 10px 12px;
  font-size: 13px;
  font-weight: 700;
  color: #888;
  border-bottom: 1px solid #333;
}

.list-header-kegs {
  grid-template-columns: 1fr 1fr 80px 120px;
}

.list-header-bevs {
  grid-template-columns: 1fr 60px 60px 50px 120px;
}

.list-body {
  margin-top: 8px;
}

.list-row {
  display: grid;
  gap: 12px;
  padding: 12px;
  align-items: center;
  background: #1a1a1a;
  border: 1px solid #2a2a2a;
  border-radius: 6px;
  margin-bottom: 8px;
  cursor: pointer;
}

.list-row:hover {
  background: #222;
  border-color: #444;
}

.list-row-keg {
  grid-template-columns: 1fr 1fr 80px 120px;
}

.list-row-bev {
  grid-template-columns: 1fr 60px 60px 50px 120px;
}

.list-row .row-name {
  font-weight: 600;
  color: #e0e0e0;
}

.list-row .row-meta {
  font-size: 14px;
  color: #888;
}

.list-row .row-actions {
  display: flex;
  gap: 8px;
}

.list-row .btn-edit,
.list-row .btn-delete {
  padding: 6px 12px;
  font-size: 12px;
  font-weight: 600;
  border-radius: 4px;
  border: none;
  cursor: pointer;
}

.list-row .btn-edit {
  background: #333;
  color: #93c5fd;
}

.list-row .btn-edit:hover {
  background: #444;
}

.list-row .btn-delete {
  background: #4a1515;
  color: #f87171;
}

.list-row .btn-delete:hover {
  background: #6b2020;
}


.keg-name-readonly {
  margin: 0 0 16px 0;
  padding: 10px 12px;
  background: #252525;
  border: 1px solid #444;
  border-radius: 4px;
  color: #e0e0e0;
  font-size: 14px;
}

.keg-calc-readonly {
  margin: 0 0 16px 0;
  padding: 10px 12px;
  background: #252525;
  border: 1px solid #444;
  border-radius: 4px;
  color: #22c55e;
  font-size: 16px;
  font-weight: 600;
}

.calc-hint {
  font-size: 12px;
  font-weight: 400;
  color: #666;
}

/* Keg modal: two-column rows for compact layout */
.keg-form-row {
  display: flex;
  gap: 12px;
  margin-bottom: 12px;
}

.keg-field {
  flex: 1;
  min-width: 0;
}

#form-keg .keg-field input,
#form-keg .keg-field .keg-calc-readonly {
  margin-bottom: 0;
}

/* Modals */
.modal {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.modal.hidden {
  display: none;
}

.modal-content {
  position: relative;
  background: #1a1a1a;
  border: 1px solid #444;
  border-radius: 10px;
  padding: 24px;
  width: 90%;
  max-width: 400px;
  max-height: calc(100vh - 48px);
  overflow-y: auto;
}

.modal-content h3 {
  margin: 0 0 20px 0;
  font-size: 18px;
  color: #ffa500;
}

.modal-content label {
  display: block;
  font-size: 12px;
  font-weight: 600;
  color: #888;
  margin-bottom: 4px;
}

.modal-content input,
.modal-content select {
  width: 100%;
  padding: 10px 12px;
  margin-bottom: 16px;
  font-size: 14px;
  background: #252525;
  border: 1px solid #444;
  border-radius: 4px;
  color: #e0e0e0;
}

.modal-content select {
  cursor: pointer;
}

/* Beverage modal: Color (SRM) row with swatch */
.bev-srm-row {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 16px;
}

.bev-srm-row input {
  flex: 1;
  margin-bottom: 0;
}

.bev-srm-swatch {
  width: 48px;
  height: 48px;
  min-width: 48px;
  border-radius: 6px;
  border: 1px solid #444;
  background: #E5A128;
}

.modal-actions {
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  margin-top: 20px;
}

.modal-actions .btn-cancel,
.modal-actions .btn-save,
.modal-actions .btn-delete {
  padding: 10px 20px;
  font-size: 14px;
  font-weight: 600;
  border-radius: 4px;
  cursor: pointer;
}

.modal-actions .btn-cancel {
  background: #333;
  color: #ccc;
  border: 1px solid #444;
}

.modal-actions .btn-cancel:hover {
  background: #444;
}

.modal-actions .btn-save {
  background: #166534;
  color: #fff;
  border: none;
}

.modal-actions .btn-save:hover {
  background: #15803d;
}

.modal-actions .btn-delete {
  background: #991b1b;
  color: #fff;
  border: none;
}

.modal-actions .btn-delete:hover {
  background: #b91c1c;
}

.modal-confirm p {
  margin: 0 0 20px 0;
  color: #e0e0e0;
}

.list-error {
  color: #f87171;
  padding: 16px;
}

/* Tap selector modal */
.modal-tap-select .tap-select-list {
  max-height: 320px;
  overflow-y: auto;
  margin-bottom: 16px;
}
.tap-select-loading {
  padding: 24px;
  text-align: center;
  color: #888;
}

.tap-select-row {
  display: block;
  width: 100%;
  padding: 14px 16px;
  font-size: 16px;
  font-weight: 600;
  color: #e0e0e0;
  background: #252525;
  border: none;
  border-bottom: 1px solid #333;
  cursor: pointer;
  text-align: left;
}

.tap-select-row:hover {
  background: #333;
}

.tap-select-row.tap-select-system {
  background: #2a2a2a;
  color: #93c5fd;
}

.tap-select-cancel {
  width: 100%;
}

/* Calibrate / Mark Empty modals */
.calibrate-grid {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 12px 24px;
  margin-bottom: 20px;
  font-size: 14px;
}

.calibrate-grid span:first-child {
  color: #888;
}

.calibrate-grid .cal-new-label {
  color: #22c55e;
  font-weight: 700;
}

.cal-new-value {
  font-size: 20px;
  font-weight: 700;
  color: #22c55e;
}

.cal-confirm-label {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px;
  background: rgba(34, 197, 94, 0.2);
  border-radius: 6px;
  margin-bottom: 20px;
  font-size: 14px;
  cursor: pointer;
}

.cal-confirm-label input {
  width: auto;
  margin: 0;
}

.keg-name-highlight {
  font-size: 18px;
  font-weight: 600;
  color: #ffa500;
  margin: 8px 0 20px 0;
}

/* SYSTEM tab — Active Taps, Units, DEMO */
.system-section {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.system-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.system-row label {
  font-size: 13px;
  font-weight: 600;
  color: #888;
  min-width: 80px;
}

.system-row select,
.system-row input[type="text"] {
  padding: 6px 10px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 4px;
  color: #e0e0e0;
  cursor: pointer;
}


.wifi-mode-section {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid #333;
}

.wifi-mode-section > label {
  display: block;
  font-size: 13px;
  color: #aaa;
  margin-bottom: 10px;
}

.wifi-mode-buttons {
  display: flex;
  gap: 8px;
}

.btn-wifi-reset {
  padding: 6px 16px;
  font-size: 13px;
  font-weight: 600;
  background: #4a1515;
  color: #f87171;
  border: 1px solid #6b2020;
  border-radius: 4px;
  cursor: pointer;
  flex: 1;
}

.btn-wifi-reset:hover:not(:disabled) {
  background: #6b2020;
}

.btn-wifi-reset:disabled {
  background: #333;
  color: #888;
  border-color: #444;
  cursor: default;
}

.main-header.standalone h1 {
  border: 2px solid #ffa500;
  border-radius: 6px;
  padding: 2px 14px;
}

/* Dev-only section (hidden in production) */
.dev-section {
  margin-top: 20px;
  padding: 12px;
  border: 1px solid #991b1b;
  border-radius: 6px;
}

.dev-label {
  display: block;
  font-size: 11px;
  font-weight: 700;
  color: #f87171;
  margin-bottom: 10px;
  letter-spacing: 0.5px;
}

.btn-connect-dev {
  padding: 6px 14px;
  font-size: 13px;
  font-weight: 600;
  background: #991b1b;
  color: #fff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

.btn-connect-dev:hover {
  background: #b91c1c;
}

.dev-section input[type="text"] {
  padding: 6px 10px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #991b1b;
  border-radius: 4px;
  color: #e0e0e0;
  width: 140px;
}

.dev-section .status {
  display: block;
  margin-top: 8px;
}

/* Settings screen */
.settings-header {
  padding: 16px;
  background: #141414;
  border-bottom: 1px solid #222;
}

.settings-header h2 {
  margin: 0;
  font-size: 20px;
  font-weight: 700;
  color: #ffa500;
}

.settings-tabs {
  display: flex;
  gap: 4px;
  padding: 10px 16px;
  background: #1a1a1a;
  flex-wrap: wrap;
}

.settings-tab-btn {
  padding: 10px 16px;
  font-size: 14px;
  font-weight: 700;
  color: #888;
  background: #252525;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.settings-tab-btn:hover {
  color: #ccc;
  background: #333;
}

.settings-tab-btn.active {
  color: #ffa500;
  background: #1a1a1a;
  border-color: #ffa500;
}

.settings-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
}

.settings-pane {
  display: none;
}

.settings-pane.active {
  display: block;
}

.alerts-section {
  margin-bottom: 24px;
}

.alerts-section h3 {
  margin: 0 0 12px 0;
  font-size: 16px;
  color: #ffa500;
}

.alerts-section label {
  display: block;
  margin: 12px 0 4px 0;
  font-size: 13px;
  color: #888;
}

.alerts-section input[type="text"],
.alerts-section input[type="email"],
.alerts-section input[type="password"],
.alerts-section select {
  width: 100%;
  max-width: 400px;
  padding: 8px 12px;
  font-size: 14px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 4px;
  color: #e0e0e0;
}

.alerts-section input[type="range"] {
  width: 100%;
  max-width: 300px;
  margin: 4px 0;
}

.btn-secondary {
  margin-top: 16px;
  padding: 10px 20px;
  font-size: 14px;
  font-weight: 600;
  background: #2a4a6a;
  color: #e0e0e0;
  border: 1px solid #3a5a7a;
  border-radius: 4px;
  cursor: pointer;
}

.btn-secondary:hover {
  background: #3a5a8a;
}

.updates-version {
  font-size: 18px;
  font-weight: 600;
  color: #ffa500;
  margin-bottom: 8px;
}

.updates-note {
  color: #888;
  font-size: 14px;
  margin-bottom: 16px;
}

.ap-mode-notice {
  background: #3a2800;
  border: 1px solid #ffc107;
  border-radius: 8px;
  padding: 12px 16px;
  color: #ffc107;
  font-size: 13px;
  line-height: 1.5;
  margin-bottom: 16px;
}

.updates-log {
  background: #0d0d0d;
  border: 1px solid #333;
  border-radius: 4px;
  padding: 12px;
  font-family: monospace;
  font-size: 12px;
  color: #a0a0a0;
  min-height: 120px;
  max-height: 200px;
  overflow-y: auto;
  white-space: pre-wrap;
  word-break: break-all;
}

.ota-progress-bar {
  margin-top: 10px;
  height: 6px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 3px;
  overflow: hidden;
}

.ota-progress-fill {
  height: 100%;
  width: 0%;
  background: #22c55e;
  border-radius: 3px;
  transition: width 0.3s ease;
}

.about-section {
  margin-bottom: 24px;
}

.about-support-row {
  display: flex;
  align-items: flex-start;
  gap: 24px;
}

.about-support-row > div {
  flex: 1;
  min-width: 0;
}

.about-support-img {
  width: 140px;
  height: 140px;
  object-fit: contain;
  flex-shrink: 0;
}

.about-section h3 {
  margin: 0 0 8px 0;
  font-size: 16px;
  color: #ffa500;
}

.about-section p {
  margin: 0;
  font-size: 14px;
  color: #ccc;
  line-height: 1.5;
}

.about-section a {
  color: #93c5fd;
  text-decoration: none;
}

.about-section a:hover {
  text-decoration: underline;
}

.cal-instructions {
  margin-bottom: 16px;
  color: #888;
}

.cal-tap-buttons {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  margin-bottom: 20px;
}

.cal-tap-btn {
  padding: 12px 20px;
  font-size: 14px;
  font-weight: 600;
  background: #252525;
  color: #888;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.cal-tap-btn:hover {
  background: #333;
  color: #ccc;
}

.cal-tap-btn.active {
  background: #2a4a6a;
  color: #93c5fd;
  border-color: #3a5a7a;
}

.cal-tap-btn.pouring {
  background: #1a4a1a;
  color: #22c55e;
  border-color: #2a6a2a;
}

.cal-tap-btn.wrong-pour {
  background: #4a1a1a;
  color: #f87171;
  border-color: #6a2a2a;
}

.cal-tap-column {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.cal-sim-buttons {
  display: flex;
  flex-direction: column;
  gap: 4px;
  width: 100%;
}

.cal-sim-buttons.hidden {
  display: none;
}

.cal-pour-btn {
  padding: 8px 12px;
  font-size: 12px;
  font-weight: 600;
  background: #333;
  color: #93c5fd;
  border: 1px solid #444;
  border-radius: 4px;
  cursor: pointer;
}

.cal-pour-btn:hover {
  background: #444;
}

.cal-main label {
  display: block;
  margin: 12px 0 4px 0;
  font-size: 13px;
  color: #888;
}

.cal-volume-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 4px 0;
}

.cal-volume-row input[type="range"] {
  flex: 1;
  min-width: 0;
}

.btn-cal-adjust {
  padding: 8px 12px;
  font-size: 14px;
  font-weight: 600;
  background: #252525;
  color: #e0e0e0;
  border: 1px solid #333;
  border-radius: 4px;
  cursor: pointer;
}

.btn-cal-adjust:hover {
  background: #333;
}

.cal-data-row {
  display: flex;
  gap: 12px;
  margin: 12px 0 16px 0;
  flex-wrap: wrap;
}

.cal-data-block {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex: 1;
  min-width: 100px;
}

.cal-data-block label {
  font-size: 13px;
  color: #888;
  margin: 0;
}

.cal-pulses {
  font-size: 24px;
  font-weight: 700;
  color: #ffa500;
}

.cal-data-block #cal-k-input {
  width: 100%;
  max-width: 120px;
  padding: 8px 12px;
  font-size: 16px;
  font-weight: 600;
  background: #252525;
  border: 1px solid #444;
  border-radius: 4px;
  color: #e0e0e0;
}

.cal-data-block #cal-k-input:not(:disabled)::-webkit-outer-spin-button,
.cal-data-block #cal-k-input:not(:disabled)::-webkit-inner-spin-button {
  opacity: 1;
}

.cal-data-block #cal-k-input:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

.cal-current-k {
  font-size: 18px;
  font-weight: 600;
  color: #ffa500;
}

.cal-checkbox-label {
  display: flex;
  align-items: center;
  gap: 8px;
  cursor: pointer;
  margin-top: 16px;
}

.cal-checkbox-label input {
  width: auto;
  margin: 0;
}
